import java.io.IOException;
import javax.servlet.ServletException;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

public class SecureServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");
        String safeOutput = sanitizeInput(userInput); // Sanitize user input

        String output = "<p>User input: " + safeOutput + "</p>"; // Output sanitized input

        response.setContentType("text/html");
        response.getWriter().println(output);
    }

    private String sanitizeInput(String input) {
        // Implement proper input sanitization to prevent XSS attacks
        if (input == null || input.isEmpty()) {
            return "";
        }

        // Encode HTML entities to prevent script injection
        return input.replaceAll("<", "&lt;")
                    .replaceAll(">", "&gt;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
